    address: result?.address,
    realizedWinRate: result?.tradingHistory?.winRate,
    totalRealizedPnL: result?.tradingHistory?.totalRealizedPnL,
    top3OpenPositionsByCurrentValue: topOpenPositions,
    fetchedAt: result?.fetchedAt
  };
}

