import { callMcpSkill } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const search = await callMcpSkill({
    toolId,
    toolName: "search_and_get_outcomes",
    args: {
      query: "Super Bowl 2026 winner",
      category: "sports"
    }
  });

  const outcomes = Array.isArray(search?.outcomes) ? search.outcomes : [];

  const shortlisted = pickTopSemanticCandidates({
    target: "Super Bowl 2026 winner outcomes",
    candidates: outcomes,
    requiredTerms: ["Super Bowl", "2026", "winner"],
    avoidTerms: ["divisional", "conference", "mvp", "prop", "touchdown"],
    limit: 3
  });

  const ranked = shortlisted
    .filter((o) => o && typeof o.name === "string" && typeof o.price === "number")
    .sort((a, b) => b.price - a.price)
    .slice(0, 3)
    .map((o, index) => ({
      rank: index + 1,
      name: o.name,
      currentYESPrice: o.price,
      pricePercent: o.pricePercent,
      tokenId: o.tokenId,
      conditionId: o.conditionId
    }));

  return {
    venue: "Polymarket",
    crossVenueComparisonAvailable: false,
    note: "Cross-venue comparison is unavailable because no other marketplace tool is available in this session. Ranking Polymarket outcomes only with live numbers.",
    eventTitle: search?.eventTitle,
    eventSlug: search?.eventSlug,
    searchMethod: search?.searchMethod,
    matchConfidence: search?.matchConfidence,
    top3Outcomes: ranked,
    fetchedAt: search?.fetchedAt
  };
}

